lib/infrastructure/auth/current_user.dart (esquema)<pre><code>class CurrentUser {
  CurrentUser({
    required this.id,
    required this.username,
    required this.email,
    required this.givenName,
    required this.familyName,
    required this.roles,
  });

  final String id;            // sub del JWT
  final String username;      // preferred_username
  final String email;
  final String givenName;
  final String familyName;
  final List&lt;String&gt; roles;

  late final Set&lt;Permission&gt; permissions = permissionsForRoles(roles);

  bool hasPermission(Permission p) =&gt; permissions.contains(p);

  factory CurrentUser.fromJwt(Map&lt;String, dynamic&gt; claims) {
    return CurrentUser(
      id: claims['sub'] as String,
      username: claims['preferred_username'] as String,
      email: claims['email'] as String,
      givenName: claims['given_name'] as String? ?? '',
      familyName: claims['family_name'] as String? ?? '',
      roles: (claims['roles'] as List?)?.cast&lt;String&gt;() ?? const [],
    );
  }
}
</code></pre>

lib/core/ui/AppPermissionGate.dart (esquema)<pre><code>class AppPermissionGate extends ConsumerWidget {
  const AppPermissionGate({
    required this.permission,
    required this.child,
    this.fallback,
    super.key,
  });

  final Permission permission;
  final Widget child;
  final Widget? fallback;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final user = ref.watch(currentUserProvider);
    if (user != null &amp;&amp; user.hasPermission(permission)) {
      return child;
    }
    return fallback ?? const SizedBox.shrink();
  }
}
</code></pre> <p>Uso en cualquier feature:</p> <pre><code>AppPermissionGate(
  permission: Permission.voluntariosCrear,
  child: AppPrimaryButton(
    label: 'Crear voluntario',
    onPressed: () =&gt; context.go('/voluntarios/nuevo'),
  ),
)
</code></pre> <p>Concentra la lógica de RBAC en un solo widget, evita esparcir <code>if (currentUser.hasPermission(...))</code> por toda la UI y permite testear con un único patrón (<code>pumpRiverpod</code> + override del <code>currentUserProvider</code> + <code>find.byType(AppPermissionGate)</code>).</p>
